func hello(name string) {
    fmt.Printf("안녕, %s!\n", name)
}

func main() {
    // go 키워드 하나로 동시 실행!
    go hello("Go")
    go hello("세계")

    // 익명 함수 고루틴
    go func() {
        fmt.Println("익명 고루틴!")
    }()
    time.Sleep(time.Second)
}

func worker(id int, wg *sync.WaitGroup) {
    defer wg.Done() // 완료 시 카운터 -1
    fmt.Printf("워커 %d 작업중\n", id)
    time.Sleep(time.Second)
    fmt.Printf("워커 %d 완료\n", id)
}
func main() {
    var wg sync.WaitGroup
    for i := 1; i <= 5; i++ {
        wg.Add(1) // 카운터 +1
        go worker(i, &wg)
    }
    wg.Wait() // 카운터 0이 될 때까지
    fmt.Println("전체 작업 완료!")
}

// ❌ 클로저 변수 캡처 문제
for i := 0; i < 3; i++ {
    go func() {
        fmt.Println(i) // 3,3,3 😱
    }()
}
// ✅ 파라미터로 전달 (해결법)
for i := 0; i < 3; i++ {
    go func(n int) {
        fmt.Println(n) // 0,1,2 ✅
    }(i)
}
// ✅ Go 1.22+ 루프변수 스코프 수정
// 각 반복마다 새 변수 생성!
// 1.22 이후는 기본 동작으로 해결

// 워커 풀: N개 워커가 작업 소비 ⭐
jobs := make(chan int, 100)
var wg sync.WaitGroup
for w := 0; w < 3; w++ {
    wg.Add(1)
    go func() {
        defer wg.Done()
        for j := range jobs {
            process(j)
        }
    }()
}
// 작업 전송 후 채널 닫기
for j := 0; j < 20; j++ { jobs <- j }
close(jobs); wg.Wait()

// errgroup: 고루틴 에러 관리 ⭐
// "golang.org/x/sync/errgroup"
g, ctx := errgroup.WithContext(ctx)
urls := []string{
    "https://api.a.com",
    "https://api.b.com",
}
for _, url := range urls {
    g.Go(func() error {
        return fetch(ctx, url)
    })
}
// 모든 완료 대기 + 첫 에러 반환
if err := g.Wait(); err != nil {
    log.Fatal(err) // 에러 전파!
}
